// Collect all inputs
const inbox = $input.all().length > 0 ? $('Fetch Inbox Items').all().map(i => i.json) : [];
const active = $('Fetch Active Items').all().map(i => i.json);
const pending = $('Fetch Pending Items').all().map(i => i.json);
const projects = $('Fetch Active Projects').all().map(i => i.json);

// Identify someday items (tagged #someday)
const somedayItems = active.filter(a => 
  Array.isArray(a.tags) && a.tags.some(t => t.name === '#someday')
);

// Identify stale items (active, not updated in 7+ days)
const now = new Date();
const weekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);
const staleItems = active.filter(a => new Date(a.updated_at) < weekAgo);

// Build digest HTML
let html = '<h2>GSD Weekly Review</h2>';
html += `<p>Generated: ${now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>`;

// Inbox
html += `<h3>Inbox (${inbox.length} unprocessed)</h3>`;
if (inbox.length > 0) {
  html += '<ul>';
  inbox.forEach(i => { html += `<li>${i.title}</li>`; });
  html += '</ul>';
  html += '<p><strong>Action:</strong> Process these in the Intake UI.</p>';
} else {
  html += '<p>Inbox zero!</p>';
}

// Stale Actions
html += `<h3>Stale Actions (${staleItems.length})</h3>`;
if (staleItems.length > 0) {
  html += '<ul>';
  staleItems.forEach(i => {
    const tags = Array.isArray(i.tags) ? i.tags.map(t => t.name).join(', ') : '';
    html += `<li>${i.title} [${tags}]</li>`;
  });
  html += '</ul>';
  html += '<p><strong>Action:</strong> Are these still relevant? Update or complete them.</p>';
} else {
  html += '<p>All active items are fresh.</p>';
}

// Pending / Waiting
html += `<h3>Pending / Waiting For (${pending.length})</h3>`;
if (pending.length > 0) {
  html += '<ul>';
  pending.forEach(i => { html += `<li>${i.title}</li>`; });
  html += '</ul>';
  html += '<p><strong>Action:</strong> Follow up on these.</p>';
} else {
  html += '<p>Nothing pending.</p>';
}

// Someday/Maybe
html += `<h3>Someday/Maybe (${somedayItems.length})</h3>`;
if (somedayItems.length > 0) {
  html += '<ul>';
  somedayItems.forEach(i => { html += `<li>${i.title}</li>`; });
  html += '</ul>';
  html += '<p><strong>Action:</strong> Scan this list. Promote or delete.</p>';
} else {
  html += '<p>No someday items.</p>';
}

// Projects
html += `<h3>Active Projects (${projects.length})</h3>`;
if (projects.length > 0) {
  html += '<ul>';
  projects.forEach(p => {
    const hasActions = active.some(a => a.project_id === p.id);
    const flag = hasActions ? '' : ' <strong>[NO NEXT ACTION]</strong>';
    html += `<li>${p.name}${flag}</li>`;
  });
  html += '</ul>';
} else {
  html += '<p>No active projects.</p>';
}

return [{ json: { subject: `GSD Weekly Review - ${now.toLocaleDateString()}`, html } }];
